public final class AsymQ4 {
    // `a` has length N.
    // Your analysis should be based on N.
    public static int f(int[] a) {
        int n = a.length;
        int s = 0;
        int k = 1;
        while (k <= n) {
            s += g(a, k);
            k = k * 2;
        }
        return s;
    }

    private static int g(int[] a, int x) {
        int t = 0;
        for (int i = 0; i < a.length; i++) {
            if (a[i] < x) t += a[i];
        }
        return t;
    }
}

Calculate the asymptotic worst case running time of the functions below, as a function of the number of nodes N in the linked list with head h.

